#nullable enable // autogenerated

using MVZ2.GameContent.Contraptions;
using MVZ2.GameContent.Stages;
using MVZ2Logic.Definitions;
using MVZ2Logic.IZombie;
using Tools;

namespace MVZ2.GameContent.IZombie
{
    [AutoIZombieLayoutDefinition(VanillaIZombieLayoutNames.izeControl2)]
    public class IZEControl2Layout : IZELayout
    {
        public IZEControl2Layout(string nsp, string name) : base(nsp, name)
        {
        }
        protected override void FillEndlessContraptions(IIZombieMap map, RandomGenerator rng)
        {
            RandomFill(map, VanillaContraptionID.hellfire, 1, rng);
            RandomFill(map, VanillaContraptionID.spikeBlock, 3, rng);
            RandomFill(map, VanillaContraptionID.gravityPad, 2, rng); // Does not count.

            RandomFill(map, VanillaContraptionID.drivenser, 1, rng);
            RandomFill(map, VanillaContraptionID.triplenser, 1, rng);
            RandomFill(map, VanillaContraptionID.repeatenser, 1, rng);
            RandomFill(map, VanillaContraptionID.transfenser, 1, rng);
            RandomFill(map, VanillaContraptionID.woodenDropper, 2, rng);
            RandomFill(map, VanillaContraptionID.pistenser, 1, rng);

            RandomFill(map, VanillaContraptionID.stoneDropper, 1, rng);
            RandomFill(map, VanillaContraptionID.gravelpult, 2, rng);
            RandomFill(map, VanillaContraptionID.fireworkDispenser, 1, rng);
            RandomFill(map, VanillaContraptionID.stoneEye, 2, rng);
        }
    }
}
